class Solution:
    def findTheLongestSubstring(self, s: str) -> int:
        vowels = set('aeiou')
        best = 0
        for i in range(len(s)):
            cnts = {v: 0 for v in vowels}
            for j in range(i, len(s)):
                if s[j] in vowels:
                    cnts[s[j]] += 1
                if all(c % 2 == 0 for c in cnts.values()):
                    best = max(best, j - i + 1)
        return best

