class Solution:
    def findTheLongestSubstring(self, s: str) -> int:
        vowel_bit = {'a': 1, 'e': 2, 'i': 4, 'o': 8, 'u': 16}
        first = {0: -1}
        mask = 0
        best = 0
        for i, c in enumerate(s):
            if c in vowel_bit:
                mask ^= vowel_bit[c]
            if mask in first:
                best = max(best, i - first[mask])
            else:
                first[mask] = i
        return best

